macro.airbnb_analytics.calculate_complet.macro_sql:
{% macro calculate_completeness(
  model,
  column_name
) %}
SELECT
  '{{ model }}' AS model_name,
  '{{ column_name }}' AS column_name,
  COUNT(*) AS total_rows,
  COUNT(
    {{ column_name }}
  ) AS non_null_rows,
  ROUND(COUNT({{ column_name }}) * 100.0 / COUNT(*), 2) AS completeness_pct
FROM
  {{ ref(model) }}
