macro.airbnb_analytics.test_no_nulls_in_.macro_sql:
{% test no_nulls_in_columns(model, column_names) %}

WITH validation AS (
    SELECT
        {% for column_name in column_names %}
        SUM(CASE WHEN {{ column_name }} IS NULL THEN 1 ELSE 0 END) AS {{ column_name }}_null_count
        {% if not loop.last %},{% endif %}
        {% endfor %}
    FROM {{ model }}
)

SELECT *
FROM validation
WHERE 
    {% for column_name in column_names %}
    {{ column_name }}_null_count > 0
    {% if not loop.last %}OR{% endif %}
    {% endfor %}

{% endtest %}

macro.airbnb_analytics.test_referential_.macro_sql:
{% test referential_integrity(model, column_name, to, field) %}
WITH child AS (
    SELECT DISTINCT {{ column_name }} AS child_key
    FROM {{ model }}
    WHERE {{ column_name }} IS NOT NULL
),
parent AS (
    SELECT DISTINCT {{ field }} AS parent_key
    FROM {{ to }}
)
-- Encontra chaves órfãs (existem no child mas não no parent)
SELECT 
    c.child_key,
    'Orphan record: exists in child but not in parent' AS error_message
FROM child c
LEFT JOIN parent p ON c.child_key = p.parent_key
WHERE p.parent_key IS NULL

{% endtest %}

